def gcd(a, b):
    if b == 0:
        return a
    return gcd(b, a % b)


def gcd_iterative(a, b):
    while b:
        a, b = b, a % b
    return a


def lcm(a, b):
    return a * b // gcd(a, b)


def extended_gcd(a, b):
    if b == 0:
        return a, 1, 0
    g, x1, y1 = extended_gcd(b, a % b)
    x = y1
    y = x1 - (a // b) * y1
    return g, x, y


def is_prime(n):
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False

    limit = int(n ** 0.5)
    for divisor in range(3, limit + 1, 2):
        if n % divisor == 0:
            return False

    return True
